// Acknowledge callback immediately
const callbackId = $input.first().json.body.callback_query?.id;
return [{ json: { callback_query_id: callbackId, skill: $input.first().json.body.callback_query?.data?.replace('approve_', '') } }];

const response = $input.first().json;
const textBlock = response.content?.find(b => b.type === 'text');
const text = textBlock?.text || '';
const match = text.match(/\{[\s\S]*"proposals"[\s\S]*\}/);
let proposals = [];
try { proposals = match ? JSON.parse(match[0]).proposals : []; } catch(e) {}
return [{ json: { proposals, count: proposals.length } }];

const proposals = $input.first().json.proposals;
const lines = proposals.map(p => `• *${p.skill}* (${p.memories} memorie)`);
const keyboard = proposals.map(p => [
  { text: '✅ ' + p.skill, callback_data: 'approve_' + p.skill },
  { text: '❌ scarta', callback_data: 'reject_' + p.skill }
]);
return [{ json: {
  text: '🧠 *Skill Sync completato*\n\n📋 ' + proposals.length + ' proposte pending:\n' + lines.join('\n') + '\n\nSeleziona cosa fare:',
  reply_markup: { inline_keyboard: keyboard }
} }];

const response = $input.first().json;
const textBlock = response.content?.find(b => b.type === 'text');
const text = textBlock?.text || '';
const match = text.match(/\{[\s\S]*"pending"[\s\S]*\}/);
let pending = [];
try { pending = match ? JSON.parse(match[0]).pending : []; } catch(e) {}
if (pending.length === 0) {
  return [{ json: { text: '📋 Nessuna proposal pending.\n\nUsa /skill-sync per generarne di nuove.', reply_markup: null } }];
}
const lines = pending.map(p => `• *${p.skill}*: _${p.preview}_`);
const keyboard = pending.map(p => [
  { text: '✅ ' + p.skill, callback_data: 'approve_' + p.skill },
  { text: '❌', callback_data: 'reject_' + p.skill }
]);
return [{ json: {
  text: '📋 *Proposals pending* (' + pending.length + '):\n\n' + lines.join('\n'),
  reply_markup: { inline_keyboard: keyboard }
} }];
